DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PCCmacros.pl", "contextFiniteSolutionSets.pl", "contextForm.pl", "contextFraction.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context("Fraction"); ($m,$c) = random_subset(2,2..12); $b = Fraction(random_coprime([1..12],[2..12])); $left = Formula("$m x + $b"); $right = Formula("$c"); $sol = ($c - $b)/$m; Context("FiniteSolutionSets"); $solution = Formula("{$sol}"); $lcd = ($b->value)[1];
############################################################ # Body ############################################################
BEGIN_PGML Solve the given equation. Practice clearing the denominator(s) as a first step.
[`[$left] = [$right]`]
[@KeyboardInstructions('What LCD will you use?')@]**
[_]{$lcd}{4}
[@KeyboardInstructions('Solve the equation.')@]**
[_]{$solution}{16}
END_PGML
############################################################ # End Problem ############################################################
